// Lee el Google Sheet CSV y devuelve la ficha de las parcelas consultadas.
// No consulta UF ni calcula nada — solo estructura lo que viene en el Sheet.

const sheetItem = $('Fetch Google Sheet CSV').first().json;
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
if (!csvText || csvText.length < 100) {
  return [{ json: {
    ok: false,
    error: 'csv_fetch_failed',
    tool_output_text: 'No pude consultar el inventario en este momento.',
  } }];
}

const input = $('Execute Workflow Trigger').first().json || {};
const numeroRaw = (input.numero ?? '').toString().trim();
const numerosQuery = numeroRaw
  ? numeroRaw.split(/[,\s]+/).map(n => n.trim().toUpperCase()).filter(Boolean)
  : [];

function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const parseMoney = (s) => {
  if (!s) return null;
  const t = s.toString();
  if (t.includes('#DIV') || t.includes('#REF') || t.includes('#VALUE')) return null;
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseSize = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseIntSafe = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return e || 'desconocido';
};

const rows = parseCsv(csvText);
const parcelas = [];
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  parcelas.push({
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normalizeEstado(r[2]),
    tamano_m2: parseSize(r[3]),
    precio_contado: parseMoney(r[6]),
    descuento_pct: parseIntSafe(r[7]),
    precio_credito: parseMoney(r[9]),
    pie_minimo_50pct: parseMoney(r[10]),
    cuota_mensual_clp: parseMoney(r[11]),
  });
}

const fmtClp = (n) => (n === null || n === undefined) ? '—' : `$${n.toLocaleString('es-CL')}`;
const fmtSize = (n) => (n === null || n === undefined) ? '—' : `${n.toLocaleString('es-CL')} m²`;

function fichaDisponible(p) {
  const lines = [
    `📍 *Lote:* ${p.numero}${p.destacada ? ' ⭐' : ''}`,
    `✅ *Estado:* Disponible`,
    `📏 *Tamaño:* ${fmtSize(p.tamano_m2)}`,
    `💵 *Precio contado:* ${fmtClp(p.precio_contado)}${p.descuento_pct ? ` (${p.descuento_pct}% dcto)` : ''}`,
    `🏦 *Precio crédito:* ${fmtClp(p.precio_credito)}`,
    `💰 *Pie mínimo 50%:* ${fmtClp(p.pie_minimo_50pct)}`,
    `🗓️ *Valor cuota (36 meses):* ${fmtClp(p.cuota_mensual_clp)}`,
  ];
  return lines.join('\n');
}

function fichaParcela(p) {
  if (p.estado === 'disponible') return fichaDisponible(p);
  if (p.estado === 'vendido') return `Parcela ${p.numero}: vendida`;
  if (p.estado === 'reservado') return `Parcela ${p.numero}: reservada`;
  return `Parcela ${p.numero}: estado no definido`;
}

if (numerosQuery.length > 0) {
  const resultados = [];
  const noEncontradas = [];

  for (const num of numerosQuery) {
    const match = parcelas.find(p => p.numero === num);
    if (!match) noEncontradas.push(num);
    else resultados.push(match);
  }

  const fichas = resultados.map(fichaParcela).join('\n\n');
  let textoSalida = fichas;

  if (noEncontradas.length > 0) {
    const nfLine = noEncontradas.length === 1
      ? `Parcela ${noEncontradas[0]}: no existe en el inventario (lotes válidos: 1–74 y B1–B20).`
      : `Parcelas no encontradas: ${noEncontradas.join(', ')} (lotes válidos: 1–74 y B1–B20).`;
    textoSalida = textoSalida ? `${textoSalida}\n\n${nfLine}` : nfLine;
  }

  return [{ json: {
    ok: resultados.length > 0,
    query: { numeros: numerosQuery },
    parcelas: resultados,
    no_encontradas: noEncontradas,
    tool_output_text: textoSalida,
  } }];
}

const disponibles = parcelas.filter(p => p.estado === 'disponible');
disponibles.sort((a, b) => {
  if (a.destacada !== b.destacada) return a.destacada ? -1 : 1;
  const pa = a.precio_contado ?? Infinity;
  const pb = b.precio_contado ?? Infinity;
  if (pa !== pb) return pa - pb;
  return a.numero.localeCompare(b.numero, 'es', { numeric: true });
});

if (disponibles.length === 0) {
  return [{ json: {
    ok: true,
    query: {},
    total_disponibles: 0,
    parcelas: [],
    tool_output_text: 'En este momento no hay parcelas disponibles.',
  } }];
}

const fichasTodas = disponibles.map(fichaDisponible).join('\n\n');
const text = `Parcelas disponibles (${disponibles.length}):\n\n${fichasTodas}`;

return [{ json: {
  ok: true,
  query: {},
  total_disponibles: disponibles.length,
  parcelas: disponibles,
  tool_output_text: text,
} }];
